using System;
using System.IO;
using System.Net;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System.Collections.Generic;
using System.Text.Json;
using System.Threading.Tasks;

public static class ReportingFunction
{
    [FunctionName("ReportingFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        log.LogInformation("Processing request for reporting API.");

        // Get connection string from application settings
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("SQL connection string is not configured.");
        }

        // Base query
        string query = "SELECT * FROM Reports";

        // Build dynamic WHERE clause from query string parameters
        List<string> conditions = new List<string>();
        foreach (var param in req.Query)
        {
            if (!string.IsNullOrWhiteSpace(param.Value))
            {
                // Direct concatenation of SQL with query string parameters
                // Assuming parameter names match column names in the Reports table
                conditions.Add($"{param.Key} = '{param.Value}'");
            }
        }
        if (conditions.Count > 0)
        {
            query += " WHERE " + string.Join(" AND ", conditions);
        }

        List<Dictionary<string, object>> results = new List<Dictionary<string, object>>();

        try
        {
            using (SqlConnection conn = new SqlConnection(connectionString))
            {
                await conn.OpenAsync();

                using (SqlCommand cmd = new SqlCommand(query, conn))
                {
                    using (SqlDataReader reader = await cmd.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            Dictionary<string, object> row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }
                }
            }
        }
        catch (Exception ex)
        {
            log.LogError("Error querying database: " + ex.Message);
            return new StatusCodeResult(StatusCodes.Status500InternalServerError);
        }

        string jsonResult = JsonSerializer.Serialize(results);
        return new OkObjectResult(jsonResult);
    }
}